 1→import { INetworkAccount } from './network-account.type';
 2→import { SupportedNetworks } from './network.type';
 3→
 4→export interface ISweepBaseParams {
 5→  fromPrivateKey: string;
 6→  fromAddress: string;
 7→  toAddress: string;
 8→  indempotencyKey: string;
 9→  // If not provided, the entire balance will be swept
10→  amount?: string;
