13→export interface INetworkService {
14→  readonly networkName: SupportedNetworks;
15→  createAccount(): Promise<INetworkAccount>;
16→
17→  /**
18→   * Sweeps base currency (TRX for Tron, ETH for Ethereum) from a one-time wallet to a destination address
19→   * @param oneTimeWalletPrivateKey Private key of the one-time wallet
20→   * @param destinationAddress Address to sweep funds to
21→   * @returns Transaction hash
22→   */
23→  sweepBase(
24→    params: ISweepBaseParams,
25→  ): Promise<{ transactionHash: string; amount: string }>;
26→
27→  /**
