29→   * @param oneTimeWalletPrivateKey Private key of the one-time wallet
30→   * @param currencyCode Currency code (e.g., 'USDT')
31→   * @param destinationAddress Address to sweep tokens to
32→   * @returns Transaction hash
33→   */
34→  sweepToken(
35→    oneTimeWalletPrivateKey: string,
36→    currencyCode: string,
37→    destinationAddress: string,
38→  ): Promise<{ transactionHash: string; amount: string }>;
39→}
