 6→import { NotificationsModule } from '@modules/notifications/notifications.module';
 7→
 8→@Module({
 9→  imports: [
10→    TronNetworkModule,
11→    EthereumNetworkModule,
12→    CurrencyModule,
13→    NotificationsModule,
14→  ],
15→  controllers: [],
16→  providers: [NetworksService],
17→  exports: [NetworksService, TronNetworkModule], // Re-export TronNetworkModule to make OutstandingTronAccountService available
