  1→import { EthereumNetworkService } from '../ethereum/services/ethereum-network.service';
  2→import { TronNetworkService } from '../tron/services/tron-network.service';
  3→import { INetworkAccount } from '../types/network-account.type';
  4→import { SupportedNetworks } from '../types/network.type';
  5→import {
  6→  BadRequestException,
  7→  Inject,
  8→  Injectable,
  9→  Logger,
 10→} from '@nestjs/common';
 11→import { CurrencyService } from '@modules/currency/services/currency.service';
 12→import { IGetTransactionHistoryParams } from '../types/network.type';
 13→import { INetworkTransaction } from '../types/network.type';
 14→import { ISweepBaseParams } from '../types/network-service';
 15→import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
 16→import { Db } from '@shared/database/types';
 17→import { NotificationsService } from '@modules/notifications/services/notifications.service';
 18→import { DEFAULT_REDIS_TOKEN } from '@configs/redis.config';
 19→import { Redis } from 'ioredis';
 20→import { SweepRecordEntity } from '@entities/balance.entity';
 21→import { Selectable } from 'kysely';
 22→import { networksConfigs } from '@configs/networks.configs';
 23→import { ConfigType } from '@nestjs/config';
 24→
 25→@Injectable()
 26→export class NetworksService {
 27→  constructor(
 28→    private readonly tronNetworkService: TronNetworkService,
 29→    private readonly ethereumNetworkService: EthereumNetworkService,
 30→    private readonly currencyService: CurrencyService,
 31→    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
 32→    private readonly notificationsService: NotificationsService,
 33→    @Inject(DEFAULT_REDIS_TOKEN)
 34→    private readonly redis: Redis,
 35→    @Inject(networksConfigs.KEY)
 36→    private readonly networksConfig: ConfigType<typeof networksConfigs>,
 37→  ) {}
 38→
 39→  private readonly logger = new Logger(NetworksService.name);
 40→
 41→  async createAccount(network: SupportedNetworks): Promise<INetworkAccount> {
 42→    switch (network) {
 43→      case SupportedNetworks.TRON:
 44→        return this.tronNetworkService.createAccount();
 45→      case SupportedNetworks.ETHEREUM:
 46→        return this.ethereumNetworkService.createAccount();
 47→      case SupportedNetworks.SOLANA:
 48→        throw new BadRequestException('Solana network is not supported yet');
 49→      default:
 50→        throw new BadRequestException('Unsupported network');
 51→    }
 52→  }
 53→
 54→  /**
 55→   * Gets the current balance of a currency at the specified address
 56→   * @param network The network to check
 57→   * @param address The address to check
 58→   * @param contractAddress The token contract address (null for native currency)
 59→   * @returns Current balance as a string
 60→   */
 61→  async getBalanceByAddress(
 62→    network: SupportedNetworks,
 63→    address: string,
 64→    contractAddress: string | null,
 65→  ): Promise<{ found: boolean; amount: string }> {
 66→    try {
 67→      let balance: string;
 68→
 69→      if (contractAddress === null) {
 70→        // Base currency (TRX, ETH, etc.)
 71→        switch (network) {
 72→          case SupportedNetworks.TRON:
 73→            balance = await this.tronNetworkService.getTrxBalance(address);
 74→            break;
 75→          case SupportedNetworks.ETHEREUM:
 76→            balance = await this.ethereumNetworkService.getBalance(address);
 77→            break;
 78→          case SupportedNetworks.SOLANA:
 79→            throw new BadRequestException(
 80→              'Solana network is not supported yet',
 81→            );
 82→          default:
 83→            throw new BadRequestException('Unsupported network');
 84→        }
 85→      } else {
 86→        // Token currency - find currency by contract address
 87→        const currencies = await this.currencyService.getCurrencies({});
 88→        const tokenCurrency = currencies.find(
 89→          (c) => c.contractAddress === contractAddress && c.network === network,
 90→        );
 91→
 92→        if (!tokenCurrency) {
 93→          throw new BadRequestException(
 94→            `Currency not found for contract address: ${contractAddress}`,
 95→          );
 96→        }
 97→
 98→        switch (network) {
 99→          case SupportedNetworks.TRON:
100→            balance = await this.tronNetworkService.getTokenBalance(
101→              address,
102→              tokenCurrency.code,
103→            );
104→            break;
105→          case SupportedNetworks.ETHEREUM:
106→            balance = await this.ethereumNetworkService.getTokenBalance(
107→              address,
108→              contractAddress,
109→              tokenCurrency.decimalPlaces,
110→            );
111→            break;
112→          case SupportedNetworks.SOLANA:
113→            throw new BadRequestException(
114→              'Solana network is not supported yet',
115→            );
116→          default:
117→            throw new BadRequestException('Unsupported network');
118→        }
119→      }
120→
121→      const amount = parseFloat(balance);
122→      return {
123→        found: amount > 0,
124→        amount: balance,
125→      };
126→    } catch (error) {
127→      this.logger.error({ error, message: 'Failed to get balance by address' });
128→      return { found: false, amount: '0' };
129→    }
130→  }
131→
132→  /**
133→   * Sweeps funds from a one-time wallet to a destination address
134→   * @param network The network to use
135→   * @param oneTimeWalletPrivateKey Private key of the one-time wallet
136→   * @param currencyCode Currency code (e.g., 'USDT', 'TRX', 'ETH')
137→   * @param destinationAddress Address to sweep funds to
138→   * @returns Transaction hash
139→   */
140→  async sweepFunds(
141→    network: SupportedNetworks,
142→    currencyCode: string,
143→    options: Required<ISweepBaseParams>,
144→  ): Promise<{ swept: boolean; transactionHash?: string; amount?: string }> {
145→    const redisKey = `sweep:${options.indempotencyKey}`;
146→    const indempotencyKeyCheck = await this.redis.getset(redisKey, '1');
147→
148→    if (indempotencyKeyCheck === '1') {
149→      throw new BadRequestException('Sweep record already exists');
150→    }
151→
152→    const existingSweepRecord = await this.db
153→      .selectFrom('sweepRecord')
154→      .selectAll()
155→      .where('indempotencyKey', '=', options.indempotencyKey)
156→      .executeTakeFirst();
157→    if (existingSweepRecord) {
158→      if (existingSweepRecord.status === 'completed') {
159→        return {
160→          swept: true,
161→          transactionHash: existingSweepRecord.transactionHash,
162→          amount: existingSweepRecord.amount,
163→        };
164→      }
165→      if (existingSweepRecord.status === 'failed') {
166→        this.notificationsService.sendNotification(
167→          `Errow sweeping funds for indempotency key: ${options.indempotencyKey}`,
168→        );
169→        throw new BadRequestException('Sweep record failed');
170→      }
171→      this.notificationsService.sendNotification(
172→        `Errow sweeping funds for indempotency key: ${options.indempotencyKey}`,
173→      );
174→      throw new BadRequestException('Sweep record already exists');
175→    }
176→    console.log({ currencyCode, network, options });
177→    // Look up currency to determine if it's a base currency (contractAddress === null) or token
178→    const currency = await this.currencyService.getCurrencyByCodeAndNetwork(
179→      currencyCode,
180→      network,
181→    );
182→
183→    if (!currency) {
184→      throw new BadRequestException(
185→        `Currency ${currencyCode} not found on ${network}`,
186→      );
187→    }
188→
189→    let transactionHash: string | undefined;
190→    let amount: string | undefined;
191→    let swept = false;
192→
193→    const sweepRecord = await this.db
194→      .insertInto('sweepRecord')
195→      .returning(['id'])
196→      .values({
197→        currencyId: currency.id,
198→        fromAddress: options.fromAddress,
199→        toAddress: options.toAddress,
200→        amount: options.amount,
201→        status: 'pending',
202→        errorMessage: null,
203→        indempotencyKey: options.indempotencyKey,
204→      })
205→      .executeTakeFirstOrThrow();
206→
207→    void this.redis.del(redisKey);
208→
209→    try {
210→      // If contractAddress is null, it's a base currency (TRX, ETH, etc.)
211→      if (currency.contractAddress === null) {
212→        switch (network) {
213→          case SupportedNetworks.TRON: {
214→            const result = await this.tronNetworkService.sweepBase(options);
215→            transactionHash = result.transactionHash;
216→            amount = result.amount;
217→            swept = true;
218→            break;
219→          }
220→          case SupportedNetworks.ETHEREUM: {
221→            const ethResult =
222→              await this.ethereumNetworkService.sweepBase(options);
223→            transactionHash = ethResult.transactionHash;
224→            amount = ethResult.amount;
225→            swept = true;
226→            break;
227→          }
228→          case SupportedNetworks.SOLANA:
229→            throw new BadRequestException(
230→              'Solana network is not supported yet',
231→            );
232→          default:
233→            throw new BadRequestException('Unsupported network');
234→        }
235→      } else {
236→        // Token currency - has contractAddress
237→        switch (network) {
238→          case SupportedNetworks.TRON: {
239→            const tronResult = await this.tronNetworkService.sweepToken(
240→              options.fromPrivateKey,
241→              currencyCode,
242→              options.toAddress,
243→            );
244→            transactionHash = tronResult.transactionHash;
245→            amount = tronResult.amount;
246→            swept = true;
247→            break;
248→          }
249→          case SupportedNetworks.ETHEREUM: {
250→            const ethResult = await this.ethereumNetworkService.sweepToken(
251→              options.fromPrivateKey,
252→              currencyCode,
253→              options.toAddress,
254→            );
255→            transactionHash = ethResult.transactionHash;
256→            amount = ethResult.amount;
257→            swept = true;
258→            break;
259→          }
260→          case SupportedNetworks.SOLANA:
261→            throw new BadRequestException(
262→              'Solana network is not supported yet',
263→            );
264→          default:
265→            throw new BadRequestException('Unsupported network');
266→        }
267→      }
268→
269→      await this.db
270→        .updateTable('sweepRecord')
271→        .set({
272→          status: 'completed',
273→          transactionHash: transactionHash,
274→        })
275→        .where('id', '=', sweepRecord.id)
276→        .execute();
277→
278→      return {
279→        swept,
280→        transactionHash,
281→        amount,
282→      };
283→    } catch (error: unknown) {
284→      await this.db
285→        .updateTable('sweepRecord')
286→        .set({
287→          status: 'failed',
288→          errorMessage:
289→            error instanceof Error ? error.message : 'Unknown error',
290→        })
291→        .where('id', '=', sweepRecord.id)
292→        .execute();
293→      throw error;
294→    }
295→  }
296→
297→  async getSweepRecord(
298→    dateFrom: Date,
299→    dateTo: Date,
300→  ): Promise<Selectable<SweepRecordEntity>[]> {
301→    return this.db
302→      .selectFrom('sweepRecord')
303→      .selectAll()
304→      .where('createdAt', '>=', dateFrom)
305→      .where('createdAt', '<=', dateTo)
306→      .execute();
307→  }
308→
309→  /**
310→   * Gets transaction history for an address to check for incoming deposits
311→   * @param network The network to check
312→   * @param address The address to get transaction history for
313→   * @param contractAddress Optional contract address for token transactions (null for base currency)
314→   * @param sinceTimestamp Optional timestamp to filter transactions after this time (in milliseconds)
315→   * @returns Array of incoming transactions
316→   */
317→  async getTransactionHistory(
318→    options: IGetTransactionHistoryParams & { network: SupportedNetworks },
319→  ): Promise<INetworkTransaction[]> {
320→    const { network, ...rest } = options;
321→    switch (network) {
322→      case SupportedNetworks.TRON:
323→        return this.tronNetworkService.getTransactionHistory(rest);
324→      case SupportedNetworks.ETHEREUM:
325→        return this.ethereumNetworkService.getTransactionHistory(rest);
326→      case SupportedNetworks.SOLANA:
327→        throw new BadRequestException('Solana network is not supported yet');
328→      default:
329→        throw new BadRequestException('Unsupported network');
330→    }
331→  }
332→
333→  async getOutstandingAccountByNetwork(
334→    network: SupportedNetworks,
335→  ): Promise<{ address: string; privateKey: string }> {
336→    switch (network) {
337→      case SupportedNetworks.TRON:
338→        return {
339→          address: this.networksConfig.tron.outstandingAccount.address,
340→          privateKey: this.networksConfig.tron.outstandingAccount.privateKey,
341→        };
342→      case SupportedNetworks.ETHEREUM:
343→        return {
344→          address: this.networksConfig.ethereum.outstandingAccount.address,
345→          privateKey:
346→            this.networksConfig.ethereum.outstandingAccount.privateKey,
347→        };
348→      case SupportedNetworks.SOLANA:
349→        throw new BadRequestException('Solana network is not supported yet');
350→      default:
351→        throw new BadRequestException('Unsupported network');
352→    }
353→  }
354→}
