 96→  /**
 97→   * Sweeps TRC-20 tokens from a one-time wallet to a destination address
 98→   * @param oneTimeWalletPrivateKey Private key of the one-time wallet
 99→   * @param currencyCode Currency code (e.g., 'USDT')
100→   * @param destinationAddress Address to sweep tokens to
101→   * @returns Transaction hash
102→   */
103→  async sweepToken(
104→    oneTimeWalletPrivateKey: string,
105→    currencyCode: string,
106→    destinationAddress: string,
107→  ): Promise<{ transactionHash: string; amount: string }> {
108→    try {
109→      // Get currency to find contract address
110→      const currency = await this.currencyService.getCurrencyByCodeAndNetwork(
111→        currencyCode,
112→        SupportedNetworks.TRON,
113→      );
114→
115→      if (!currency || !currency.contractAddress) {
116→        throw new Error(
117→          `Currency ${currencyCode} not found or missing contract address`,
118→        );
119→      }
120→
121→      const contractAddress = currency.contractAddress;
122→
123→      // Create wallet from private key
124→      const wallet = this.tronWeb.address.fromPrivateKey(
125→        oneTimeWalletPrivateKey,
126→      );
127→
128→      // Create contract instance using standard TRC-20 ABI to get balance
129→      const contract = this.tronWeb.contract(TRC20_ABI.entrys, contractAddress);
130→
131→      // Get balance of the one-time wallet
132→      const balance = await contract.methods
133→        .balanceOf(wallet)
134→        .call({ from: wallet });
135→
136→      if (balance.toString() === '0') {
137→        throw new Error('No tokens to sweep');
138→      }
139→
140→      // Use triggerSmartContract as per TronWeb documentation
141→      // https://tronweb.network/docu/docs/Transfer%20Token/
142→      const functionSelector = 'transfer(address,uint256)';
143→      const parameter = [
144→        { type: 'address', value: destinationAddress },
145→        { type: 'uint256', value: balance.toString() },
146→      ];
147→
148→      // Set feeLimit for TRC-20 transfers (consumes energy)
149→      const feeLimit = 18_000_000; // 18 TRX in SUN
150→
151→      // Build the transaction using triggerSmartContract
152→      const tx = await this.tronWeb.transactionBuilder.triggerSmartContract(
153→        contractAddress,
154→        functionSelector,
155→        { feeLimit }, // Options object with feeLimit
156→        parameter,
157→        wallet as string, // issuerAddress - the address that will sign and send the transaction
158→      );
159→
160→      // Sign the transaction with the private key
161→      const signedTx = await this.tronWeb.trx.sign(
162→        tx.transaction,
163→        oneTimeWalletPrivateKey,
164→      );
165→
166→      // Send the signed transaction
167→      const result = await this.tronWeb.trx.sendRawTransaction(signedTx);
168→
169→      // Extract transaction hash from result
170→      if (result.result) {
171→        const txHash = result.txid || tx.transaction?.txID || '';
172→        return { transactionHash: txHash, amount: balance.toString() };
173→      } else {
174→        throw new Error(
175→          `Transaction failed: ${result.message || 'Unknown error'}`,
176→        );
177→      }
178→    } catch (error) {
179→      const errorMessage =
180→        error instanceof Error ? error.message : String(error);
181→      throw new Error(`Failed to sweep token: ${errorMessage}`);
182→    }
183→  }
184→
185→  /**
186→   * Sweeps TRX from a one-time wallet to a destination address
187→   * @param oneTimeWalletPrivateKey Private key of the one-time wallet
188→   * @param destinationAddress Address to sweep TRX to
189→   * @returns Transaction hash
190→   */
191→  async sweepBase(
192→    params: ISweepBaseParams,
193→  ): Promise<{ transactionHash: string; amount: string }> {
194→    try {
195→      // Create wallet from private key
196→      const wallet = this.tronWeb.address.fromPrivateKey(params.fromPrivateKey);
197→
198→      // Get balance (in SUN, 1 TRX = 1,000,000 SUN)
199→      const balance = await this.tronWeb.trx.getBalance(wallet);
200→
201→      if (balance === 0) {
202→        throw new Error('No TRX to sweep');
203→      }
204→
205→      //const sendAmount = new Decimal(params.amount).mul(1_000_000).toNumber();
206→
207→      // Calculate amount to send (subtract transaction fee)
208→      // Current TRX transfer fee is ~1.1 TRX
209→      // Using 1,200,000 SUN (1.2 TRX) as a safe buffer for fees
210→      const fee = 1_200_000; // 1.2 TRX in SUN (safe buffer, actual fee ~1.1 TRX)
211→      const availableBalance = new Decimal(balance)
212→        .minus(fee)
213→        .minus(params.amount ?? 0)
214→        .toNumber();
215→      //.minus(sendAmount).toNumber());
216→
217→      if (availableBalance <= 0) {
218→        throw new Error('Insufficient balance after fee deduction');
219→      }
220→
221→      let sendAmount = params.amount
222→        ? new Decimal(params.amount).mul(1_000_000)
223→        : new Decimal(availableBalance);
224→
225→      // Transfer TRX to destination
226→      // According to TronWeb docs, use sendTrx() for TRX transfers
227→      // sendTrx() handles transaction creation, signing, and broadcasting automatically
228→      const tx = await this.tronWeb.trx.sendTrx(
229→        params.toAddress,
230→        parseFloat(sendAmount.toString()),
231→        {
232→          privateKey: params.fromPrivateKey,
233→        },
234→      );
235→
236→      return {
237→        transactionHash: tx.txid,
238→        amount: sendAmount.div(1_000_000).toString(),
239→      };
240→    } catch (error) {
241→      const errorMessage =
242→        error instanceof Error ? error.message : String(error);
243→      throw new Error(`Failed to sweep TRX: ${errorMessage}`);
244→    }
245→  }
